const jobs = $json.jobs || [];
return jobs.map(j => ({
  json: {
    source: 'jobicy',
    external_id: String(j.id ?? ''),
    company: j.companyName || '',
    title: j.jobTitle || '',
    location: j.jobGeo || 'remote',
    remote: 'remote',
    url: j.url || '',
    description: (j.jobDescription || '').replace(/<[^>]*>/g, '').slice(0, 5000),
    posted_at: j.pubDate ? new Date(j.pubDate).toISOString() : null,
  }
}));

function simpleHash(str) {
  let hash = 0;
  for (let i = 0; i < str.length; i++) {
    hash = ((hash << 5) - hash) + str.charCodeAt(i);
    hash |= 0;
  }
  return Math.abs(hash).toString(16).padStart(8, '0');
}
return items.map(({ json }) => {
  const base = [json.source, json.external_id, json.company, json.title, json.url].join('|');
  return { json: { ...json, content_hash: simpleHash(base) } };
});
